function trocarFiltro(filtro, btnEl) {
    document.querySelectorAll('.cxh-filtro-btn').forEach(b => b.classList.remove('ativo'));
    btnEl.classList.add('ativo');
    carregarCaixinhas(filtro);
}

// ════════════════════════════════════════════════════════════════
// MODAL DETALHES
// ════════════════════════════════════════════════════════════════
function abrirModalDetalhes(c) {
    _caixinhaAtual = c;
    const encerrada = !c.isAtiva;

    // Cabeçalho
    document.getElementById('detNome').textContent    = c.nome;
    document.getElementById('detDesc').textContent    = c.descricao || '';
    document.getElementById('detBadge').className     = `cxh-badge cxh-badge-${c.tipoRendimento || 'CDI'}`;
    document.getElementById('detBadge').textContent   = labelTipo(c.tipoRendimento);
    document.getElementById('detStatusBadge').innerHTML = encerrada
        ? `<span style="font-size:0.7rem;font-weight:700;padding:3px 9px;border-radius:12px;background:var(--cor-fundo-inativo);color:var(--cor-texto-secundario);">Encerrada</span>`
        : `<span style="font-size:0.7rem;font-weight:700;padding:3px 9px;border-radius:12px;background:var(--green-100);color:var(--green-700);">Ativa</span>`;

    // Stats
    document.getElementById('detValorAtual').textContent  = formatarMoeda(c.valorAtual ?? 0);
    document.getElementById('detMeta').textContent        = formatarMoeda(c.valorMeta ?? 0);
    document.getElementById('detFalta').textContent       = formatarMoeda(c.faltaParaMeta ?? 0);
    const pct = c.percentualAtingido ?? 0;
    document.getElementById('detPct').textContent         = `${pct.toFixed(1)}%`;
    document.getElementById('detMeses').textContent       = c.mesesRestantes != null ? `${c.mesesRestantes} meses` : '–';
    document.getElementById('detPrazo').textContent       = c.dataPrazo ? formatarData(c.dataPrazo) : '–';
    document.getElementById('detAporte').textContent      = c.aporteMensalSugerido != null ? formatarMoeda(c.aporteMensalSugerido) : '–';
    document.getElementById('detTaxaMensal').textContent  = c.taxaMensalEfetiva != null
        ? `${(c.taxaMensalEfetiva * 100).toFixed(4)}% a.m.`
        : '–';

    // Barra de progresso
    const fillPct = Math.min(100, pct);
    document.getElementById('detProgressoFill').style.width = `${fillPct}%`;
    document.getElementById('detPctBar').textContent = `${pct.toFixed(1)}%`;

    // Meta alcançável
    const alcDiv = document.getElementById('detAlcancavel');
    if (typeof c.metaAlcancavel === 'boolean') {
        alcDiv.innerHTML = `
            <span class="cxh-det-alcancavel ${c.metaAlcancavel ? '' : 'nao'}">
                <i class='bx ${c.metaAlcancavel ? 'bx-check-circle' : 'bx-x-circle'}'></i>
                ${c.metaAlcancavel ? 'Meta alcançável com aportes sugeridos' : 'Meta pode não ser atingida com os aportes atuais'}
            </span>`;
    } else {
        alcDiv.innerHTML = '';
    }

    // Projeção
    document.getElementById('detProjecao').innerHTML = gerarTextoProjecao(c);

    // Instituições
    const instLista = document.getElementById('detInstLista');
    const instSection = document.getElementById('detInstSection');
    if (c.instituicoes && c.instituicoes.length > 0) {
        instSection.style.display = '';
        instLista.innerHTML = c.instituicoes.map(inst =>
            `<div class="cxh-det-inst-item">
                <span class="cxh-det-inst-nome"><i class='bx bx-buildings'></i> ${escHtml(inst.nome || 'Instituição')}</span>
                <span class="cxh-det-inst-val">${formatarMoeda(inst.valorAportado ?? 0)}</span>
            </div>`
        ).join('');
    } else {
        instSection.style.display = 'none';
    }

    // Botões: mostrar Encerrar OU Reabrir conforme status
    const btnEnc = document.getElementById('btnDetEncerrar');
    const btnReab = document.getElementById('btnDetReabrir');
    if (encerrada) {
        btnEnc.style.display  = 'none';
        btnReab.style.display = '';
    } else {
        btnEnc.style.display  = '';
        btnReab.style.display = 'none';
    }

    document.getElementById('modalDetOverlay').classList.add('aberto');
}

function fecharModalDet() {
    document.getElementById('modalDetOverlay').classList.remove('aberto');
    // Resetar footer de confirmação
    const fnormal = document.getElementById('detFooterNormal');
    const fconf   = document.getElementById('detFooterConfirmacao');
    if (fnormal) fnormal.style.display = 'flex';
    if (fconf)   fconf.style.display   = 'none';
    _caixinhaAtual = null;
}

function fecharModalDetOutside(e) {
    if (e.target === document.getElementById('modalDetOverlay')) fecharModalDet();
}

function gerarTextoProjecao(c) {
    const semAportes = c.montanteProjetadoSemAportes;
    const comAportes = c.montanteProjetadoComAportes;
    const aporte     = c.aporteMensalSugerido;
    const meses      = c.mesesRestantes;
    const taxa       = c.taxaMensalEfetiva;

    // Calcular projeção localmente se os dados do servidor estiverem ausentes
    const r = taxa != null ? taxa : 0;
    const n = meses != null ? meses : 0;
    const VA = c.valorAtual ?? 0;

    // Projeção sem aportes: VA * (1+r)^n
    const projSemAp = semAportes != null ? semAportes : (r > 0 ? VA * Math.pow(1 + r, n) : VA);
    // Projeção com aportes sugeridos
    const ap = aporte != null ? aporte : 0;
    const projComAp = comAportes != null ? comAportes
        : (r > 0 ? projSemAp + ap * ((Math.pow(1 + r, n) - 1) / r)
                 : projSemAp + ap * n);

    return `
        <strong>Sem novos aportes:</strong> você terá <strong>${formatarMoeda(projSemAp)}</strong> no prazo.<br>
        <strong>Com aporte de ${formatarMoeda(ap)}/mês:</strong> você terá <strong>${formatarMoeda(projComAp)}</strong>.<br>
        <strong>Meta:</strong> ${formatarMoeda(c.valorMeta ?? 0)}&nbsp;·&nbsp;
        <strong>Falta:</strong> ${formatarMoeda(c.faltaParaMeta ?? 0)}&nbsp;·&nbsp;
        <strong>Taxa mensal:</strong> ${r > 0 ? (r * 100).toFixed(4) + '% a.m.' : 'sem rendimento definido'}
    `;
}

// ── Ações do modal de detalhes ─────────────────────────────────
function editarCaixinhaAtual() {
    if (!_caixinhaAtual) return;
    const c = _caixinhaAtual; // salva referência ANTES de fechar (fecharModalDet zera _caixinhaAtual)
    fecharModalDet();
    abrirModalEditar(c);
}

// Exibe confirmação inline (sem confirm() nativo)
function pedirConfirmacaoReabrir() {
    if (!_caixinhaAtual) return;
    document.getElementById('detConfirmacaoTexto').textContent =
        `Reabrir "${_caixinhaAtual.nome}"? A caixinha voltará a aparecer como ativa.`;
    document.getElementById('btnConfirmarAcao').className = 'btn-cxh-reabrir-confirmar';
    document.getElementById('btnConfirmarAcao').onclick = confirmarReabrir;
    document.getElementById('detFooterNormal').style.display = 'none';
    document.getElementById('detFooterConfirmacao').style.display = 'flex';
}

async function confirmarReabrir() {
    const c = _caixinhaAtual;
    if (!c) return;
    cancelarConfirmacao();
    fecharModalDet();
    await reabrirCaixinha(c.id);
}

async function reabrirCaixinha(id) {
    try {
        const res = await MainAPI.request(`/caixinhas/${id}/reabrir`, { method: 'PATCH' });
        if (res.ok) {
            mostrarToast('Caixinha reaberta com sucesso!', 'sucesso');
            await Promise.all([carregarKPIs(), carregarCaixinhas(_filtroAtivo)]);
        } else {
            mostrarToast(`Erro ao reabrir: ${res.status}`, 'erro');
        }
    } catch (e) {
        mostrarToast('Erro de conexão ao reabrir.', 'erro');
    }
}

function pedirConfirmacaoEncerrar() {
    if (!_caixinhaAtual) return;
    document.getElementById('detConfirmacaoTexto').textContent =
        `Encerrar "${_caixinhaAtual.nome}"? Os dados serão mantidos.`;
    document.getElementById('btnConfirmarAcao').className = 'btn-cxh-encerrar-confirmar';
    document.getElementById('btnConfirmarAcao').onclick = confirmarEncerrar;
    document.getElementById('detFooterNormal').style.display = 'none';
    document.getElementById('detFooterConfirmacao').style.display = 'flex';
}

function pedirConfirmacaoDeletar() {
    if (!_caixinhaAtual) return;
    document.getElementById('detConfirmacaoTexto').textContent =
        `Deletar permanentemente "${_caixinhaAtual.nome}"? Ação irreversível.`;
    document.getElementById('btnConfirmarAcao').className = 'btn-cxh-deletar-confirmar';
    document.getElementById('btnConfirmarAcao').onclick = confirmarDeletar;
    document.getElementById('detFooterNormal').style.display = 'none';
    document.getElementById('detFooterConfirmacao').style.display = 'flex';
}

function cancelarConfirmacao() {
    document.getElementById('detFooterNormal').style.display = 'flex';
    document.getElementById('detFooterConfirmacao').style.display = 'none';
}

async function confirmarEncerrar() {
    const c = _caixinhaAtual;
    if (!c) return;
    cancelarConfirmacao();
    fecharModalDet();
    await encerrarCaixinha(c.id);
}

async function confirmarDeletar() {
    const c = _caixinhaAtual;
    if (!c) return;
    cancelarConfirmacao();
    fecharModalDet();
    await deletarCaixinha(c.id);
}

// Mantidas por compatibilidade (não usam mais confirm() nativo)
async function encerrarCaixinhaAtual() { pedirConfirmacaoEncerrar(); }
async function deletarCaixinhaAtual()  { pedirConfirmacaoDeletar(); }

// ════════════════════════════════════════════════════════════════
// MODAL CRIAR / EDITAR
// ════════════════════════════════════════════════════════════════
function abrirModalCriar() {
    _editandoId = null;
    document.getElementById('modalCriarTitulo').innerHTML = "<i class='bx bx-plus-circle'></i> Nova Caixinha";
    resetarFormulario();
    document.getElementById('modalCriarOverlay').classList.add('aberto');
    validarBotaoSalvar();
}

function abrirModalEditar(c) {
    _editandoId = c.id;
    document.getElementById('modalCriarTitulo').innerHTML = "<i class='bx bx-edit'></i> Editar Caixinha";
    preencherFormulario(c);
    document.getElementById('modalCriarOverlay').classList.add('aberto');
    validarBotaoSalvar();
}

function fecharModalCriar() {
    document.getElementById('modalCriarOverlay').classList.remove('aberto');
}

function fecharModalCriarOutside(e) {
    if (e.target === document.getElementById('modalCriarOverlay')) fecharModalCriar();
}

function resetarFormulario() {
    document.getElementById('inputNome').value        = '';
    document.getElementById('inputDescricao').value   = '';
    MainAPI.resetarMascaraMoeda(document.getElementById('inputValorMeta'));
    document.getElementById('inputDataPrazo').value   = '';
    document.getElementById('inputPctRendimento').value  = '';
    document.getElementById('inputTaxaRef').value        = '';
    document.getElementById('inputTaxaRefPoupanca').value = '';
    document.getElementById('inputTaxaAnual').value      = '';
    _instsSelecionadas.clear();
    selecionarTipoRendimento('CDI');
    renderizarInstituicoes();
    document.getElementById('taxaResumo').style.display = 'none';
}

function preencherFormulario(c) {
    document.getElementById('inputNome').value      = c.nome || '';
    document.getElementById('inputDescricao').value = c.descricao || '';

    // Valor meta
    const inputMeta = document.getElementById('inputValorMeta');
    const centavos  = Math.round((c.valorMeta ?? 0) * 100);
    inputMeta.dataset.centavos = String(centavos);
    const reais = Math.floor(centavos / 100);
    const cts   = String(centavos % 100).padStart(2, '0');
    const reaisStr = String(reais).replace(/\B(?=(\d{3})+(?!\d))/g, '.');
    inputMeta.value = `R$ ${reaisStr},${cts}`;

    // Data prazo — backend pode retornar string "aaaa-mm-dd" ou array [ano, mes, dia]
    if (c.dataPrazo) {
        let iso = c.dataPrazo;
        if (Array.isArray(iso) && iso.length >= 3) {
            iso = `${iso[0]}-${String(iso[1]).padStart(2,'0')}-${String(iso[2]).padStart(2,'0')}`;
        }
        document.getElementById('inputDataPrazo').value = MainAPI.dataDeISO(String(iso));
    }

    // Tipo de rendimento
    const tipo = c.tipoRendimento || 'CDI';
    selecionarTipoRendimento(tipo);

    if (tipo === 'CDI' || tipo === 'SELIC') {
        document.getElementById('inputPctRendimento').value  = c.percentualRendimento ?? 100;
        document.getElementById('inputTaxaRef').value        = c.taxaReferenciaAtual ?? TAXA_DEFAULTS[tipo];
    } else if (tipo === 'POUPANCA') {
        document.getElementById('inputTaxaRefPoupanca').value = c.taxaReferenciaAtual ?? TAXA_DEFAULTS.POUPANCA;
    } else {
        document.getElementById('inputTaxaAnual').value = c.taxaAnualPersonalizada ?? '';
    }

    calcularTaxaEfetiva();

    // Instituições
    _instsSelecionadas.clear();
    if (c.instituicoes && Array.isArray(c.instituicoes)) {
        c.instituicoes.forEach(inst => {
            // inst.id pode ser o id da vinculação (instituicaoUsuarioId)
            _instsSelecionadas.add(inst.id);
        });
    }
    renderizarInstituicoes();
}

// ── Tipo de rendimento ─────────────────────────────────────────
function selecionarTipoRendimento(tipo) {
    _tipoRendimento = tipo;

    // Atualizar botões
    document.querySelectorAll('.cxh-rend-btn').forEach(btn => {
        btn.className = 'cxh-rend-btn';
        if (btn.dataset.tipo === tipo) btn.classList.add(`ativo-${tipo}`);
    });

    // Mostrar campos corretos
    ['camposCdiSelic', 'camposPoupanca', 'camposPrefixado'].forEach(id => {
        document.getElementById(id).classList.remove('visivel');
    });

    if (tipo === 'CDI' || tipo === 'SELIC') {
        document.getElementById('camposCdiSelic').classList.add('visivel');
        const lbl = document.getElementById('labelPctCdi');
        const lbl2 = document.getElementById('labelTaxaRef');
        lbl.textContent  = tipo === 'CDI' ? '% do CDI' : '% da SELIC';
        lbl2.textContent = tipo === 'CDI' ? 'Taxa CDI atual (% a.a.)' : 'Taxa SELIC atual (% a.a.)';
        // Preencher default se vazio
        const inp = document.getElementById('inputTaxaRef');
        if (!inp.value) inp.value = TAXA_DEFAULTS[tipo];
        const inpPct = document.getElementById('inputPctRendimento');
        if (!inpPct.value) inpPct.value = 100;
    } else if (tipo === 'POUPANCA') {
        document.getElementById('camposPoupanca').classList.add('visivel');
        const inp = document.getElementById('inputTaxaRefPoupanca');
        if (!inp.value) inp.value = TAXA_DEFAULTS.POUPANCA;
    } else {
        document.getElementById('camposPrefixado').classList.add('visivel');
    }

    calcularTaxaEfetiva();
}

// ── Calcular taxa efetiva ──────────────────────────────────────
function calcularTaxaEfetiva() {
    const tipo = _tipoRendimento;
    let taxaAnual = 0;

    if (tipo === 'CDI' || tipo === 'SELIC') {
        const pct     = parseFloat(document.getElementById('inputPctRendimento').value) || 100;
        const taxaRef = parseFloat(document.getElementById('inputTaxaRef').value) || 0;
        taxaAnual = taxaRef * (pct / 100);
    } else if (tipo === 'POUPANCA') {
        const taxaRef = parseFloat(document.getElementById('inputTaxaRefPoupanca').value) || 0;
        taxaAnual = taxaRef * 0.70;
    } else {
        taxaAnual = parseFloat(document.getElementById('inputTaxaAnual').value) || 0;
    }

    const taxaMensal = taxaAnual > 0 ? (Math.pow(1 + taxaAnual / 100, 1 / 12) - 1) * 100 : 0;

    const resumo = document.getElementById('taxaResumo');
    const txt    = document.getElementById('taxaResumoTexto');

    if (taxaAnual > 0) {
        resumo.style.display = 'flex';
        txt.innerHTML = `Taxa efetiva: <strong>${taxaAnual.toFixed(2)}% a.a.</strong> · <strong>${taxaMensal.toFixed(4)}% a.m.</strong>`;

        // Verificar alcançabilidade em tempo real
        const meta    = MainAPI.obterValorMoeda(document.getElementById('inputValorMeta'));
        const prazoTxt = document.getElementById('inputDataPrazo').value;
        if (meta > 0 && prazoTxt && prazoTxt.length === 10) {
            const prazoISO = MainAPI.dataParaISO(prazoTxt);
            if (prazoISO) {
                const hoje    = new Date();
                const prazo   = new Date(prazoISO);
                const diffMs  = prazo - hoje;
                const meses   = Math.max(0, Math.floor(diffMs / (1000 * 60 * 60 * 24 * 30.4)));
                if (meses > 0) {
                    const r   = taxaMensal / 100;
                    const VA  = 0; // sem valor atual inicial no form
                    const projSem = r > 0 ? VA * Math.pow(1 + r, meses) : VA;
                    const aporteNecessario = r > 0
                        ? ((meta - projSem) * r) / (Math.pow(1 + r, meses) - 1)
                        : (meta - projSem) / meses;
                    if (aporteNecessario > 0) {
                        txt.innerHTML += ` · Aporte necessário: <strong>${formatarMoeda(aporteNecessario)}/mês</strong> por <strong>${meses} meses</strong>`;
                    }
                }
            }
        }
    } else {
        resumo.style.display = 'none';
    }
}

// ── Instituições ───────────────────────────────────────────────
async function carregarInstituicoes() {
    try {
        _todasInstituicoes = await MainAPI.getInstituicoes(_usuario.id);
        if (!Array.isArray(_todasInstituicoes)) _todasInstituicoes = [];
        renderizarInstituicoes();
    } catch (e) {
        console.error('Erro ao carregar instituições:', e);
        _todasInstituicoes = [];
    }
}

function renderizarInstituicoes() {
    const grid = document.getElementById('instGrid');
    if (_todasInstituicoes.length === 0) {
        grid.innerHTML = '<span style="font-size:0.82rem;color:var(--cor-texto-secundario);">Nenhuma instituição vinculada. <a href="configurações.html" style="color:var(--cor-principal);">Configurar</a></span>';
        return;
    }

    grid.innerHTML = _todasInstituicoes.map(inst => {
        const selecionada = _instsSelecionadas.has(inst.id);
        return `
        <div class="cxh-inst-item ${selecionada ? 'selecionada' : ''}" 
             data-instid="${inst.id}"
             onclick="toggleInstituicao(${inst.id}, this)">
            <span class="cxh-inst-check">${selecionada ? '✓' : ''}</span>
            <span>${escHtml(inst.intituicao?.nome || inst.instituicao?.nome || inst.nomeInstituicao || inst.nome || `Inst. ${inst.id}`)}</span>
        </div>`;
    }).join('');
}

function toggleInstituicao(instId, el) {
    if (_instsSelecionadas.has(instId)) {
        _instsSelecionadas.delete(instId);
        el.classList.remove('selecionada');
        el.querySelector('.cxh-inst-check').textContent = '';
    } else {
        _instsSelecionadas.add(instId);
        el.classList.add('selecionada');
        el.querySelector('.cxh-inst-check').textContent = '✓';
    }
    validarBotaoSalvar();
}

// ── Validar botão salvar ───────────────────────────────────────
function validarBotaoSalvar() {
    const nome    = (document.getElementById('inputNome').value || '').trim();
    const temInst = _instsSelecionadas.size > 0;
    const btn     = document.getElementById('btnSalvarCaixinha');
    const aviso   = document.getElementById('instAviso');

    btn.disabled = !(nome && temInst);
    if (aviso) aviso.style.display = (!temInst && nome) ? '' : 'none';
}

// ════════════════════════════════════════════════════════════════
// SALVAR (POST / PUT)
// ════════════════════════════════════════════════════════════════
async function salvarCaixinha() {
    const nome     = document.getElementById('inputNome').value.trim();
    const descricao = document.getElementById('inputDescricao').value.trim();
    const valorMeta = MainAPI.obterValorMoeda(document.getElementById('inputValorMeta'));
    const prazoTxt  = document.getElementById('inputDataPrazo').value;
    const tipo      = _tipoRendimento;

    if (!nome) { mostrarToast('Informe o nome da caixinha.', 'erro'); return; }
    if (_instsSelecionadas.size === 0) { mostrarToast('Selecione ao menos uma instituição.', 'erro'); return; }

    // Montar payload
    const payload = {
        usuarioId:    _usuario.id,
        nome,
        descricao:    descricao || null,
        valorMeta:    valorMeta > 0 ? valorMeta : null,
        dataPrazo:    prazoTxt ? MainAPI.dataParaISO(prazoTxt) : null,
        tipoRendimento: tipo,
        isCompartilhada: false,
        instituicaoUsuarioIds: Array.from(_instsSelecionadas)
    };

    // Campos condicionais de rendimento
    if (tipo === 'CDI' || tipo === 'SELIC') {
        payload.percentualRendimento  = parseFloat(document.getElementById('inputPctRendimento').value) || 100;
        payload.taxaReferenciaAtual   = parseFloat(document.getElementById('inputTaxaRef').value) || TAXA_DEFAULTS[tipo];
        payload.taxaAnualPersonalizada = null;
    } else if (tipo === 'POUPANCA') {
        payload.percentualRendimento  = 70;
        payload.taxaReferenciaAtual   = parseFloat(document.getElementById('inputTaxaRefPoupanca').value) || TAXA_DEFAULTS.POUPANCA;
        payload.taxaAnualPersonalizada = null;
    } else {
        payload.percentualRendimento  = 100;
        payload.taxaReferenciaAtual   = null;
        payload.taxaAnualPersonalizada = parseFloat(document.getElementById('inputTaxaAnual').value) || null;
    }

    const btn = document.getElementById('btnSalvarCaixinha');
    btn.disabled = true;
    btn.innerHTML = "<i class='bx bx-loader-alt bx-spin'></i> Salvando...";

    try {
        let res;
        if (_editandoId) {
            res = await MainAPI.request(`/caixinhas/${_editandoId}`, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(payload)
            });
        } else {
            res = await MainAPI.request('/caixinhas', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(payload)
            });
        }

        if (res.ok || res.status === 201) {
            fecharModalCriar();
            mostrarToast(_editandoId ? 'Caixinha atualizada com sucesso!' : 'Caixinha criada com sucesso!', 'sucesso');
            await Promise.all([carregarKPIs(), carregarCaixinhas(_filtroAtivo)]);
        } else {
            const err = await res.text().catch(() => '');
            mostrarToast(`Erro ao salvar: ${res.status}. ${err}`, 'erro');
        }
    } catch (e) {
        console.error('Erro ao salvar caixinha:', e);
        mostrarToast('Erro de conexão ao salvar.', 'erro');
    } finally {
        btn.disabled = false;
        btn.innerHTML = "<i class='bx bx-save'></i> Salvar";
        validarBotaoSalvar();
    }
}

// ════════════════════════════════════════════════════════════════
// ENCERRAR / DELETAR
// ════════════════════════════════════════════════════════════════
async function encerrarCaixinha(id) {
    try {
        const res = await MainAPI.request(`/caixinhas/${id}/encerrar`, { method: 'PATCH' });
        if (res.ok) {
            mostrarToast('Caixinha encerrada.', 'sucesso');
            await Promise.all([carregarKPIs(), carregarCaixinhas(_filtroAtivo)]);
        } else {
            mostrarToast(`Erro ao encerrar: ${res.status}`, 'erro');
        }
    } catch (e) {
        mostrarToast('Erro de conexão ao encerrar.', 'erro');
    }
}

async function deletarCaixinha(id) {
    try {
        const res = await MainAPI.request(`/caixinhas/${id}`, { method: 'DELETE' });
        if (res.ok || res.status === 204) {
            mostrarToast('Caixinha deletada.', 'sucesso');
            await Promise.all([carregarKPIs(), carregarCaixinhas(_filtroAtivo)]);
        } else {
            mostrarToast(`Erro ao deletar: ${res.status}`, 'erro');
        }
    } catch (e) {
        mostrarToast('Erro de conexão ao deletar.', 'erro');
    }
}

// ════════════════════════════════════════════════════════════════
// INSIGHT
// ════════════════════════════════════════════════════════════════
function mostrarInsight(lista) {
    const insightEl = document.getElementById('cxhInsight');
    const textoEl   = document.getElementById('cxhInsightTexto');

    if (!lista || lista.length === 0) {
        insightEl.style.display = 'none';
        return;
    }

    const ativas  = lista.filter(c => c.isAtiva);
    const qtd     = ativas.length;
    const alcanc  = ativas.filter(c => c.metaAlcancavel === true).length;
    const proxima = [...ativas].sort((a, b) => (a.faltaParaMeta ?? 0) - (b.faltaParaMeta ?? 0))[0];

    let texto = `Você tem <strong>${qtd}</strong> caixinha(s) ativa(s). `;
    if (alcanc > 0) texto += `<strong>${alcanc}</strong> delas com meta alcançável no prazo. `;
    if (proxima) texto += `A mais próxima da meta é <strong>"${escHtml(proxima.nome)}"</strong> (${(proxima.percentualAtingido ?? 0).toFixed(1)}% atingido, faltam ${formatarMoeda(proxima.faltaParaMeta ?? 0)}).`;

    textoEl.innerHTML = texto;
    insightEl.style.display = 'flex';
}

// ════════════════════════════════════════════════════════════════
// UTILITÁRIOS
// ════════════════════════════════════════════════════════════════
function formatarMoeda(valor) {
    const n = Number(valor) || 0;
    return n.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
}

function formatarData(iso) {
    if (!iso) return '–';
    // Suporta array [ano,mes,dia] ou string "aaaa-mm-dd"
    if (Array.isArray(iso) && iso.length >= 3) {
        return `${String(iso[2]).padStart(2,'0')}/${String(iso[1]).padStart(2,'0')}/${iso[0]}`;
    }
    const m = String(iso).match(/^(\d{4})-(\d{2})-(\d{2})/);
    if (m) return `${m[3]}/${m[2]}/${m[1]}`;
    return iso;
}

function labelTipo(tipo) {
    const map = {
        CDI: 'CDI', SELIC: 'SELIC', POUPANCA: 'Poupança',
        PREFIXADO: 'Prefixado', PERSONALIZADO: 'Personalizado'
    };
    return map[tipo] || tipo;
}

function escHtml(str) {
    if (!str) return '';
    return String(str)
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;');
}

// Toast
function mostrarToast(msg, tipo) {
    const existing = document.querySelector('.cxh-toast');
    if (existing) existing.remove();

    const toast = document.createElement('div');
    toast.className = `cxh-toast ${tipo || ''}`;
    toast.innerHTML = `<i class='bx ${tipo === 'sucesso' ? 'bx-check-circle' : 'bx-error-circle'}'></i> ${escHtml(msg)}`;
    document.body.appendChild(toast);

    setTimeout(() => {
        toast.style.transition = 'opacity 0.3s';
        toast.style.opacity = '0';
        setTimeout(() => toast.remove(), 320);
    }, 3500);
}

// ── DASHBOARD — integração com os novos endpoints /dashboard/* ────────────────
const API_BASE = 'http://localhost:8080';
const CURRENCY = new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' });

const semDados = `
  <div class="aviso">
    <i class='bx bx-search-alt'></i>
    <h3>Sem Dados</h3>
    <p>Selecione outro período para visualizar.</p>
  </div>`;

const carregando = `<p style="text-align:center;padding:32px;color:var(--cor-texto-secundario);">
    <i class='bx bx-loader-alt' style="font-size:1.5rem;animation:spin 1s linear infinite;"></i>
</p>`;

// Instâncias ApexCharts para destroy/recreate
const graficos = {};

// Período selecionado
let periodoCfg = null;

// ── Google Charts — controle de carregamento ──────────────────────────────────
let _gcReady = false;
const _gcQueue = [];
window._onGoogleChartsReady = function () {
    _gcReady = true;
    _gcQueue.forEach(fn => { try { fn(); } catch(e) { console.error('[Sankey]', e); } });
    _gcQueue.length = 0;
};

// ── HELPERS ───────────────────────────────────────────────────────────────────

function obterUsuarioIdDashboard() {
    try {
        const u = JSON.parse(localStorage.getItem('usuarioLogado') || 'null');
        return u?.id || null;
    } catch (_) { return null; }
}

function nomeMes(mes) {
    return ['Janeiro','Fevereiro','Março','Abril','Maio','Junho',
            'Julho','Agosto','Setembro','Outubro','Novembro','Dezembro'][(mes - 1)] || '';
}

function buildParams(cfg) {
    cfg = cfg || periodoCfg;
    const p = new URLSearchParams();
    p.set('periodo', cfg.tipo);
    p.set('ano', cfg.ano);
    if (cfg.tipo === 'MENSAL'     && cfg.mes)       p.set('mes',       cfg.mes);
    if (cfg.tipo === 'TRIMESTRAL' && cfg.trimestre) p.set('trimestre', cfg.trimestre);
    if (cfg.tipo === 'SEMESTRAL'  && cfg.semestre)  p.set('semestre',  cfg.semestre);
    return p.toString();
}

function labelPeriodoCfg(cfg) {
    cfg = cfg || periodoCfg;
    if (!cfg) return '';
    if (cfg.tipo === 'MENSAL')     return `${nomeMes(cfg.mes)} / ${cfg.ano}`;
    if (cfg.tipo === 'TRIMESTRAL') return `${cfg.trimestre}º Trimestre / ${cfg.ano}`;
    if (cfg.tipo === 'SEMESTRAL')  return `${cfg.semestre}º Semestre / ${cfg.ano}`;
    return `Anual / ${cfg.ano}`;
}

async function apiFetch(url) {
    try {
        // cache: 'no-store' garante dados frescos após importação de arquivos
        const res = await fetch(url, { cache: 'no-store' });
        if (res.status === 204) return { ok: false, json: null };
        if (!res.ok) {
            console.warn(`[Dashboard] API ${res.status} →`, url);
            return { ok: false, json: null };
        }
        const json = await res.json();
        return { ok: true, json };
    } catch (err) {
        console.error('[Dashboard] Erro ao buscar:', url, err);
        return { ok: false, json: null };
    }
}

function cssVar(name) {
    return getComputedStyle(document.documentElement).getPropertyValue(name).trim();
}

function isDark() {
    return document.body.dataset.mode === 'dark';
}

function clampPercent(v) {
    const n = Number(v ?? 0);
    if (!Number.isFinite(n)) return 0;
    return Math.max(0, Math.min(100, Math.round(n)));
}

function setProgress(elId, percentual) {
    const el = document.getElementById(elId);
    if (!el) return;
    el.style.width = `${clampPercent(percentual)}%`;
}

function formatarNivelSaude(nivel) {
    const n = String(nivel || '').toUpperCase();
    if (!n) return 'Sem dados no período';
    if (n === 'ATENCAO') return 'Atenção';
    if (n === 'CRITICO') return 'Crítico';
    if (n === 'BAIXO') return 'Baixo';
    if (n === 'NORMAL') return 'Normal';
    return n;
}

// Interpola hue 240(azul) → 0(vermelho) baseado em normalizado (0-1)
function heatColor(normalizado) {
    const n = Math.max(0, Math.min(1, normalizado || 0));
    if (n < 0.02) return 'var(--cor-fundo-inativo)';
    const hue = Math.round(240 * (1 - n));
    return `hsl(${hue}, 80%, ${isDark() ? 38 : 45}%)`;
}

/**
 * Retorna 3 cores para gráficos de múltiplas séries baseadas nas variáveis do root.
 * Série 1 → --cor-principal, Série 2 → --cor-para-destacar, Série 3 → --cor-hover
 */
function getChartPalette3() {
    return [
        cssVar('--cor-principal')     || '#367373',
        cssVar('--cor-para-destacar') || '#004C58',
        cssVar('--cor-hover')         || '#B4D9D5',
    ];
}

/**
 * Retorna a cor de borda do grid dos gráficos baseada na variável --cor-tinte-borda.
 */
function getGridColor() {
    return cssVar('--cor-tinte-borda') || 'rgba(54,115,115,0.18)';
}

/**
 * Retorna o array de cores dos nós do diagrama Sankey baseado nas variáveis do root.
 */
function getSankeyNodeColors() {
    const c1 = cssVar('--cor-principal')      || '#367373';
    const c2 = cssVar('--cor-para-destacar')  || '#004C58';
    const c3 = cssVar('--cor-fundo-cadastro') || '#5FA8A3';
    const c4 = cssVar('--cor-titulo')         || '#004C58';
    const c5 = cssVar('--cor-hover')          || '#B4D9D5';
    return [c1, c2, c3, c4, c5, c1, c2, c3];
}

/**
 * Retorna a cor secundária do gráfico de comparação de acordo com o tema atual.
 * Deve contrastar visivelmente com --cor-principal em qualquer combinação tema/modo.
 */
function getGraficoAntColor() {
    const tema = document.body.dataset.tema || 'padrao';
    const mode = document.body.dataset.mode || 'light';
    const map = {
        'padrao-light':    '#F59E0B',   // âmbar — contrasta com teal
        'padrao-dark':     '#FBBF24',   // âmbar claro
        'vampirico-light': '#1D4ED8',   // azul — contrasta com vermelho
        'vampirico-dark':  '#60A5FA',   // azul claro
        'ceu-azul-light':  '#7C3AED',   // roxo — contrasta com ciano
        'ceu-azul-dark':   '#A78BFA',   // roxo claro
        'purpura-light':   '#059669',   // verde — contrasta com roxo
        'purpura-dark':    '#34D399',   // verde claro
        'branco-light':    '#F59E0B',   // âmbar
        'branco-dark':     '#FBBF24',   // âmbar claro
    };
    return map[`${tema}-${mode}`] || '#F59E0B';
}

// ── ATALHOS DE PERÍODO ────────────────────────────────────────────────────────

function marcarAtalhoAtivo(atalho) {
    document.querySelectorAll('.dash-atalho-btn').forEach(btn => {
        btn.classList.toggle('ativo', btn.dataset.atalho === atalho);
    });
}

function selecionarRapido(atalho) {
    const hoje = new Date();
    const anoAtual = hoje.getFullYear();
    const mesAtual = hoje.getMonth() + 1;
    const selTipo      = document.getElementById('select_tempo');
    const selMes       = document.getElementById('select_mes');
    const selAno       = document.getElementById('select_ano');
    const divMes       = document.getElementById('div_mes');
    const divTrimestre = document.getElementById('div_trimestre');
    const divSemestre  = document.getElementById('div_semestre');

    if (divMes)       divMes.style.display       = 'none';
    if (divTrimestre) divTrimestre.style.display  = 'none';
    if (divSemestre)  divSemestre.style.display   = 'none';

    if (atalho === 'mes-atual') {
        selTipo.value = 'MENSAL';
        selMes.value  = String(mesAtual);
        selAno.value  = String(anoAtual);
        if (divMes) divMes.style.display = '';
    } else if (atalho === 'mes-passado') {
        let mes = mesAtual - 1, ano = anoAtual;
        if (mes === 0) { mes = 12; ano--; }
        selTipo.value = 'MENSAL';
        selMes.value  = String(mes);
        selAno.value  = String(ano);
        if (divMes) divMes.style.display = '';
    } else if (atalho === 'ano-atual') {
        selTipo.value = 'ANUAL';
        selAno.value  = String(anoAtual);
    } else if (atalho === 'ano-passado') {
        selTipo.value = 'ANUAL';
        selAno.value  = String(anoAtual - 1);
    }
    marcarAtalhoAtivo(atalho);
    carregarDashboard();
}

// ── INICIALIZAÇÃO ─────────────────────────────────────────────────────────────

/** Força atualização completa de KPIs e gráficos sem cache. */
function atualizarDashboard() {
    if (!periodoCfg) return;
    gerarKPIS();
    gerarGraficos();
}

/**
 * Observa mudanças de tema/modo na tag <body> e re-renderiza todos
 * os gráficos para aplicar as novas cores imediatamente.
 */
let _temaDebounce = null;
const _temaObserver = new MutationObserver(() => {
    clearTimeout(_temaDebounce);
    _temaDebounce = setTimeout(() => {
        if (!periodoCfg) return;
        // Destroi todas as instâncias ApexCharts existentes
        Object.keys(graficos).forEach(id => {
            try { graficos[id].destroy(); } catch (_) {}
            delete graficos[id];
        });
        // Re-renderiza com as novas cores do tema
        gerarGraficos();
    }, 200);
});
_temaObserver.observe(document.body, {
    attributes: true,
    attributeFilter: ['data-mode', 'data-tema']
});

async function gerarInformações() {
    const hoje = new Date();
    const anoAtual = hoje.getFullYear();
    const mesAtual = hoje.getMonth() + 1;
    periodoCfg = { tipo: 'MENSAL', ano: anoAtual, mes: mesAtual };

    const selTipo = document.getElementById('select_tempo');
    const selMes  = document.getElementById('select_mes');
    const selAno  = document.getElementById('select_ano');
    if (selTipo) selTipo.value = 'MENSAL';
    if (selMes)  selMes.value  = String(mesAtual);

    // Popula o select de ano com os anos presentes no banco
    await popularSelectAnos(selAno, anoAtual);

    atualizarSeletoresPeriodo(false);
    marcarAtalhoAtivo('mes-atual');
    carregarDashboard();
}

async function popularSelectAnos(selAno, anoAtual) {
    if (!selAno) return;
    const userId = obterUsuarioIdDashboard();
    let anos = [anoAtual];
    if (userId) {
        try {
            const { ok, json } = await apiFetch(`${API_BASE}/dashboard/anos/usuarios/${userId}`);
            if (ok && Array.isArray(json) && json.length > 0) anos = json;
        } catch (_) { /* fallback: usa só o ano atual */ }
    }
    selAno.innerHTML = anos.map(a =>
        `<option value="${a}"${a === anoAtual ? ' selected' : ''}>${a}</option>`
    ).join('');
}

function atualizarSeletoresPeriodo(recarregar) {
    const tipo = document.getElementById('select_tempo')?.value || 'MENSAL';
    const divMes       = document.getElementById('div_mes');
    const divTrimestre = document.getElementById('div_trimestre');
    const divSemestre  = document.getElementById('div_semestre');
    if (divMes)       divMes.style.display       = tipo === 'MENSAL'     ? '' : 'none';
    if (divTrimestre) divTrimestre.style.display  = tipo === 'TRIMESTRAL' ? '' : 'none';
    if (divSemestre)  divSemestre.style.display   = tipo === 'SEMESTRAL'  ? '' : 'none';
    if (recarregar !== false) { marcarAtalhoAtivo(null); carregarDashboard(); }
}

function carregarDashboard() {
    const tipo = document.getElementById('select_tempo')?.value;
    const ano  = Number(document.getElementById('select_ano')?.value);
    if (!tipo || !ano || isNaN(ano)) return;

    const cfg = { tipo, ano };
    if (tipo === 'MENSAL') {
        const mes = Number(document.getElementById('select_mes')?.value);
        if (!mes) return;
        cfg.mes = mes;
    } else if (tipo === 'TRIMESTRAL') {
        const trimestre = Number(document.getElementById('select_trimestre')?.value);
        if (!trimestre) return;
        cfg.trimestre = trimestre;
    } else if (tipo === 'SEMESTRAL') {
        const semestre = Number(document.getElementById('select_semestre')?.value);
        if (!semestre) return;
        cfg.semestre = semestre;
    }

    periodoCfg = cfg;
    const labelEl = document.getElementById('labelPeriodoAtual');
    if (labelEl) labelEl.textContent = labelPeriodoCfg(cfg);

    gerarKPIS();
    gerarGraficos();
}

// ── KPIs ──────────────────────────────────────────────────────────────────────

async function gerarKPIS() {
    const userId = obterUsuarioIdDashboard();
    if (!userId || !periodoCfg) return;
    const params = buildParams();
    await Promise.all([
        carregarHistoriaFinanceira(userId, params),
        carregarKpiSaldoTotal(userId, params),
        carregarKpiGastoTotal(userId, params),
        carregarKpiMaiorGasto(userId, params),
        carregarKpiCategoriaImpacto(userId, params),
        carregarKpiSaudeFinanceira(userId, params),
        carregarKpiPoupanca(userId),
        carregarKpiEmprestimo(userId)
    ]);
}

async function carregarHistoriaFinanceira(userId, params) {
    const elTitulo = document.getElementById('historiaTitulo');
    const elResumo = document.getElementById('historiaResumo');
    if (!elTitulo || !elResumo) return;

    elTitulo.textContent = 'História financeira do período';
    elResumo.textContent = 'Carregando...';

    const { ok, json } = await apiFetch(`${API_BASE}/dashboard/historia-financeira/usuarios/${userId}?${params}`);
    if (!ok || !json) {
        elTitulo.textContent = 'História financeira do período';
        elResumo.textContent = 'Sem dados no período.';
        return;
    }

    elTitulo.textContent = json.titulo || 'História financeira do período';
    elResumo.textContent = json.resumo || 'Sem dados no período.';
}

async function carregarKpiSaldoTotal(userId, params) {
    const el = document.getElementById('saldoTotal');
    if (!el) return;
    el.textContent = '...';
    const { ok, json } = await apiFetch(`${API_BASE}/dashboard/kpi/saldo-total/usuarios/${userId}?${params}`);
    if (!ok || !json) { el.textContent = '–'; el.style.color = ''; return; }
    const saldo = Number(json.saldo ?? 0);
    el.textContent  = CURRENCY.format(saldo);
    el.style.color  = '';
}

async function carregarKpiGastoTotal(userId, params) {
    const elValor = document.getElementById('gastoTotal');
    const elBadge = document.getElementById('percentual');
    const elSub   = document.getElementById('subtexto');
    if (!elValor) return;
    elValor.textContent = '...';

    const { ok, json } = await apiFetch(`${API_BASE}/dashboard/kpi/gasto-total/usuarios/${userId}?${params}`);
    if (!ok || !json) {
        elValor.textContent = '–';
        if (elBadge) elBadge.style.display = 'none';
        if (elSub)   elSub.textContent = '';
        return;
    }

    elValor.textContent = CURRENCY.format(Number(json.totalGastos ?? 0));
    const v = Number(json.variacaoPercentual ?? 0);
    if (!elBadge || !elSub) return;

    if (v === 0) {
        elBadge.style.display = 'none';
        elSub.textContent = 'Sem variação em relação ao período anterior';
    } else if (v > 0) {
        elBadge.style.display = '';
        elBadge.style.backgroundColor = cssVar('--red-100');
        elBadge.style.color           = cssVar('--red-700');
        elBadge.innerHTML = `<i class='bx bx-caret-big-up'></i> +${v}%`;
        elSub.textContent = `Em comparação ao ${json.labelPeriodoAnterior || 'período anterior'}`;
    } else {
        elBadge.style.display = '';
        elBadge.style.backgroundColor = cssVar('--green-100');
        elBadge.style.color           = cssVar('--green-700');
        elBadge.innerHTML = `<i class='bx bx-caret-big-down'></i> ${v}%`;
        elSub.textContent = `Em comparação ao ${json.labelPeriodoAnterior || 'período anterior'}`;
    }
}

async function carregarKpiMaiorGasto(userId, params) {
    const elSub    = document.getElementById('categoria');      // subtítulo (titulo do gasto)
    const elValor  = document.getElementById('valorCategoria'); // valor R$
    const elBadge  = document.getElementById('tituloGasto');    // badge verde "X% Do total"
    if (!elSub) return;
    elSub.textContent = '...';

    const { ok, json } = await apiFetch(`${API_BASE}/dashboard/kpi/maior-gasto/usuarios/${userId}?${params}`);
    if (!ok || !json) {
        elSub.textContent = 'Sem dados';
        if (elValor) elValor.textContent = '–';
        if (elBadge) elBadge.style.display = 'none';
        return;
    }

    // Mostra título do gasto como subtítulo e categoria entre parênteses
    elSub.textContent  = json.titulo || '–';
    if (elValor) elValor.textContent = CURRENCY.format(Number(json.valor ?? 0));
    if (elBadge) {
        if (json.percentualDoTotal != null) {
            elBadge.textContent   = `${json.percentualDoTotal}% Do total · ${json.categoria || ''}`;
            elBadge.style.display = '';
        } else {
            elBadge.style.display = 'none';
        }
    }
}

async function carregarKpiCategoriaImpacto(userId, params) {
    const elCateg   = document.getElementById('percentualKPItipo'); // nome da categoria
    const elValor   = document.getElementById('valorKPItipo');      // valor atual
    const elBadge   = document.getElementById('kpi4-badge');        // badge de variação
    const elSub     = document.getElementById('variacaoCategoriaImpacto');
    if (!elCateg) return;
    elCateg.textContent = '...';

    const { ok, json } = await apiFetch(`${API_BASE}/dashboard/kpi/categoria-impacto/usuarios/${userId}?${params}`);
    if (!ok || !json) {
        elCateg.textContent = 'Sem dados';
        if (elValor) elValor.textContent = '–';
        if (elBadge) elBadge.style.display = 'none';
        if (elSub)   elSub.textContent = '';
        return;
    }

    elCateg.textContent = json.categoria || '–';
    if (elValor) elValor.textContent = CURRENCY.format(Number(json.valorAtual ?? 0));

    const v = Number(json.variacaoPercentual ?? 0);
    if (!elBadge || !elSub) return;

    if (v === 0) {
        elBadge.style.display = 'none';
        elSub.textContent = 'Sem variação em relação ao período anterior';
    } else if (v > 0) {
        elBadge.style.display = '';
        elBadge.style.backgroundColor = cssVar('--red-100');
        elBadge.style.color           = cssVar('--red-700');
        elBadge.innerHTML = `<i class='bx bx-caret-big-up'></i> +${v}%`;
        elSub.textContent = 'Em comparação ao período anterior';
    } else {
        elBadge.style.display = '';
        elBadge.style.backgroundColor = cssVar('--green-100');
        elBadge.style.color           = cssVar('--green-700');
        elBadge.innerHTML = `<i class='bx bx-caret-big-down'></i> ${v}%`;
        elSub.textContent = 'Em comparação ao período anterior';
    }
}

async function carregarKpiSaudeFinanceira(userId, params) {
    const elPontuacao = document.getElementById('saudePontuacao');
    const elNivel = document.getElementById('saudeNivel');
    const elDesc = document.getElementById('saudeDescricao');
    if (!elPontuacao || !elNivel || !elDesc) return;

    elPontuacao.textContent = '--';
    elNivel.textContent = 'Carregando...';
    elDesc.textContent = 'Carregando...';
    setProgress('saudeProgress', 0);

    const { ok, json } = await apiFetch(`${API_BASE}/dashboard/kpi/saude-financeira/usuarios/${userId}?${params}`);
    if (!ok || !json) {
        elPontuacao.textContent = '--';
        elNivel.textContent = 'Sem dados no período';
        elDesc.textContent = 'Sem dados no período.';
        return;
    }

    const pontuacao = clampPercent(json.pontuacao);
    elPontuacao.textContent = `${pontuacao}/100`;
    elNivel.textContent = formatarNivelSaude(json.nivel);
    elDesc.textContent = json.descricao || 'Sem dados no período.';
    setProgress('saudeProgress', pontuacao);
}

async function carregarKpiPoupanca(userId) {
    const elNome = document.getElementById('poupancaNome');
    const elValor = document.getElementById('poupancaValor');
    const elMeta = document.getElementById('poupancaMeta');
    const elPct = document.getElementById('poupancaPercentual');
    if (!elNome || !elValor || !elMeta || !elPct) return;

    elNome.textContent = 'Carregando...';
    elValor.textContent = '...';
    elMeta.textContent = '...';
    elPct.textContent = '0%';
    setProgress('poupancaProgress', 0);

    const { ok, json } = await apiFetch(`${API_BASE}/dashboard/kpi/poupanca/usuarios/${userId}`);
    if (!ok || !json) {
        elNome.textContent = 'Sem dados no período';
        elValor.textContent = 'R$ 0,00';
        elMeta.textContent = 'Meta: R$ 0,00';
        elPct.textContent = '0%';
        return;
    }

    const guardado = Number(json.valorGuardado ?? 0);
    const meta = Number(json.valorMeta ?? 0);
    const pct = clampPercent(json.percentualMeta ?? 0);

    elNome.textContent = json.nomeCaixinha || 'Poupança';
    elValor.textContent = CURRENCY.format(guardado);
    elMeta.textContent = `Meta: ${CURRENCY.format(meta)} · Faltante: ${CURRENCY.format(Number(json.valorFaltante ?? 0))}`;
    elPct.textContent = `${pct}%`;
    setProgress('poupancaProgress', pct);
}

async function carregarKpiEmprestimo(userId) {
    const elInst = document.getElementById('emprestimoInstituicao');
    const elValor = document.getElementById('emprestimoValor');
    const elResumo = document.getElementById('emprestimoResumo');
    const elPct = document.getElementById('emprestimoPercentual');
    if (!elInst || !elValor || !elResumo || !elPct) return;

    elInst.textContent = 'Carregando...';
    elValor.textContent = '...';
    elResumo.textContent = 'Carregando...';
    elPct.textContent = '0%';
    setProgress('emprestimoProgress', 0);

    const { ok, json } = await apiFetch(`${API_BASE}/dashboard/kpi/emprestimo/usuarios/${userId}`);
    if (!ok || !json || !json.temEmprestimoAtivo) {
        elInst.textContent = 'Sem empréstimo ativo';
        elValor.textContent = 'R$ 0,00';
        elResumo.textContent = 'Sem dados no período.';
        elPct.textContent = '0%';
        return;
    }

    const pct = clampPercent(json.percentualQuitado ?? 0);
    const valorRestante = Number(json.valorRestante ?? 0);
    const parcelasPagas = Number(json.parcelasPagas ?? 0);
    const parcelasTotal = Number(json.parcelasTotal ?? 0);

    elInst.textContent = json.nomeInstituicao || 'Instituição';
    elValor.textContent = `Restante: ${CURRENCY.format(valorRestante)}`;
    elResumo.textContent = `Pago: ${CURRENCY.format(Number(json.valorPago ?? 0))} · ${parcelasPagas}/${parcelasTotal} parcelas`;
    elPct.textContent = `${pct}% quitado`;
    setProgress('emprestimoProgress', pct);
}

// ── GRÁFICOS ─────────────────────────────────────────────────────────────────

function gerarGraficos() {
    const userId = obterUsuarioIdDashboard();
    if (!userId || !periodoCfg) return;

    // Verifica se ApexCharts carregou (local ou CDN)
    if (typeof ApexCharts === 'undefined') {
        console.error('[Dashboard] ApexCharts não carregado — tentando CDN de fallback...');
        const s = document.createElement('script');
        s.src = 'https://cdn.jsdelivr.net/npm/apexcharts/dist/apexcharts.min.js';
        s.onload = () => { gerarGraficos(); };
        s.onerror = () => {
            ['graficoTemporal','graficoComparacao','graficoTipo','graficoDiaSemana'].forEach(id => {
                const el = document.getElementById(id);
                if (el) el.innerHTML = `<div class="aviso"><i class='bx bx-error'></i>
                    <h3>Biblioteca não disponível</h3>
                    <p>Não foi possível carregar o mecanismo de gráficos (ApexCharts).</p></div>`;
            });
        };
        document.head.appendChild(s);
        return;
    }

    const params = buildParams();
    carregarGraficoEvolucao(userId, params);
    carregarGraficoComparacao(userId, params);
    carregarGraficoCategorias(userId, params);
    carregarGraficoDiaSemana(userId, params);
    carregarGraficoFluxo(userId, params);
}

function destroyGrafico(id) {
    if (graficos[id]) { graficos[id].destroy(); delete graficos[id]; }
}

function apexTheme() {
    return isDark() ? 'dark' : 'light';
}

// ── Gráfico 1: Evolução dos gastos + recebimentos (area) ─────────────────────
async function carregarGraficoEvolucao(userId, params) {
    const el = document.getElementById('graficoTemporal');
    if (!el) return;
    el.innerHTML = carregando;

    const { ok, json } = await apiFetch(`${API_BASE}/dashboard/grafico/evolucao-gastos/usuarios/${userId}?${params}`);
    if (!ok || !json?.dados?.length) { el.innerHTML = semDados; return; }

    destroyGrafico('graficoTemporal');
    el.innerHTML = '';

    const corGastos = cssVar('--cor-principal') || '#367373';
    const corRec    = cssVar('--green-700') || '#15803D';

    const series = [{ name: 'Gastos', data: json.dados.map(d => Number(d.valor)) }];
    const colors = [corGastos];

    const hasRec = Array.isArray(json.dadosRecebimentos) && json.dadosRecebimentos.length > 0;
    if (hasRec) {
        series.push({ name: 'Recebimentos', data: json.dadosRecebimentos.map(d => Number(d.valor)) });
        colors.push(corRec);
    }

    try {
        graficos['graficoTemporal'] = new ApexCharts(el, {
            chart: { type: 'area', height: 320, toolbar: { show: false }, zoom: { enabled: false } },
            series,
            xaxis: { categories: json.dados.map(d => d.label), labels: { rotate: -35 } },
            yaxis: { labels: { formatter: v => `R$ ${Number(v).toFixed(0)}` } },
            colors,
            fill: { type: 'gradient', gradient: { shadeIntensity: 1, opacityFrom: 0.45, opacityTo: 0.04 } },
            stroke: { curve: 'smooth', width: 3 },
            dataLabels: { enabled: false },
            legend: { position: 'top' },
            grid: { borderColor: getGridColor(), strokeDashArray: 4 },
            tooltip: { theme: apexTheme(), y: { formatter: v => CURRENCY.format(v) } }
        });
        graficos['graficoTemporal'].render();
    } catch (e) {
        console.error('[Dashboard] Erro ao renderizar graficoTemporal:', e);
        el.innerHTML = semDados;
    }
}

// ── Gráfico 2: Comparação por período (multi-line) ────────────────────────────
async function carregarGraficoComparacao(userId, params) {
    const el = document.getElementById('graficoComparacao');
    if (!el) return;
    el.innerHTML = carregando;

    const { ok, json } = await apiFetch(`${API_BASE}/dashboard/grafico/comparacao-periodo/usuarios/${userId}?${params}`);
    if (!ok || !json?.dados?.length) { el.innerHTML = semDados; return; }

    destroyGrafico('graficoComparacao');
    el.innerHTML = '';

    try {
        graficos['graficoComparacao'] = new ApexCharts(el, {
            chart: { type: 'line', height: 320, toolbar: { show: false }, zoom: { enabled: false } },
            series: [
                { name: json.labelPeriodoAtual    || 'Período atual',    data: json.dados.map(d => Number(d.valorAtual)) },
                { name: json.labelPeriodoAnterior || 'Período anterior', data: json.dados.map(d => Number(d.valorAnterior)) }
            ],
            xaxis: { categories: json.dados.map(d => d.label), labels: { rotate: -35 } },
            yaxis: { labels: { formatter: v => `R$ ${Number(v).toFixed(0)}` } },
            stroke: { curve: 'smooth', width: [3, 3] },
            colors: [cssVar('--cor-principal') || '#367373', getGraficoAntColor()],
            grid: { borderColor: getGridColor(), strokeDashArray: 4 },
            legend: { position: 'top' },
            tooltip: { theme: apexTheme(), y: { formatter: v => CURRENCY.format(v) } }
        });
        graficos['graficoComparacao'].render();
    } catch (e) {
        console.error('[Dashboard] Erro ao renderizar graficoComparacao:', e);
        el.innerHTML = semDados;
    }
}

// ── Gráfico 3: Gastos por Categoria — 3 séries agrupadas ─────────────────────
async function carregarGraficoCategorias(userId, params) {
    const el = document.getElementById('graficoTipo');
    if (!el) return;
    el.innerHTML = carregando;

    const { ok, json } = await apiFetch(`${API_BASE}/dashboard/grafico/categorias/usuarios/${userId}?${params}`);
    if (!ok || !json?.categorias?.length) { el.innerHTML = semDados; return; }

    const cats   = json.categorias;
    const nomes  = cats.map(c => c.nome);
    const valores   = cats.map(c => Number(c.valorTotal));
    const pcts      = cats.map(c => Number(c.percentualDoTotal));
    const ocorrs    = cats.map(c => Number(c.ocorrencias));

    destroyGrafico('graficoTipo');
    el.innerHTML = '';

    try {
        graficos['graficoTipo'] = new ApexCharts(el, {
            chart: { type: 'bar', height: 350, toolbar: { show: false } },
            series: [
                { name: 'Valor (R$)',   data: valores, yAxisIndex: 0 },
                { name: '% do Total',  data: pcts,    yAxisIndex: 1 },
                { name: 'Ocorrências', data: ocorrs,  yAxisIndex: 1 }
            ],
            xaxis: { categories: nomes },
            yaxis: [
                {
                    seriesName: 'Valor (R$)',
                    title: { text: 'Valor (R$)', style: { color: cssVar('--cor-texto-secundario') } },
                    labels: { formatter: v => `R$ ${Number(v).toFixed(0)}` }
                },
                {
                    seriesName: '% do Total',
                    opposite: true,
                    title: { text: '% / Qtd', style: { color: cssVar('--cor-texto-secundario') } },
                    labels: { formatter: v => Number(v).toFixed(0) },
                    min: 0
                },
                {
                    seriesName: 'Ocorrências',
                    opposite: true,
                    show: false
                }
            ],
            colors: getChartPalette3(),
            plotOptions: { bar: { horizontal: false, borderRadius: 4, dataLabels: { position: 'center' } } },
            dataLabels: {
                enabled: true,
                formatter: function(val, opts) {
                    const idx = opts.seriesIndex;
                    if (idx === 0) return `R$ ${Number(val).toFixed(0)}`;
                    if (idx === 1) return `${Number(val).toFixed(0)}%`;
                    return `${Number(val).toFixed(0)}x`;
                },
                style: { fontSize: '10px', colors: [cssVar('--cor-texto-claro') || '#fff'] }
            },
            legend: { position: 'top' },
            grid: { borderColor: getGridColor(), strokeDashArray: 4 },
            tooltip: {
                theme: apexTheme(),
                shared: true,
                intersect: false,
                y: {
                    formatter: function(val, { seriesIndex }) {
                        if (seriesIndex === 0) return CURRENCY.format(val);
                        if (seriesIndex === 1) return `${val}%`;
                        return `${val} vez(es)`;
                    }
                }
            }
        });
        graficos['graficoTipo'].render();
    } catch (e) {
        console.error('[Dashboard] Erro ao renderizar graficoTipo:', e);
        el.innerHTML = semDados;
    }
}

// ── Gráfico 4: Dia da semana (heat map) ou Mês (ANUAL — bar chart) ────────────
async function carregarGraficoDiaSemana(userId, params) {
    const el       = document.getElementById('graficoDiaSemana');
    const tituloEl = document.getElementById('tituloDiaSemana');
    const tooltipEl = document.getElementById('tooltipDiaSemana');
    if (!el) return;

    // Para ANUAL → mostra gastos por mês em vez de dia da semana
    if (periodoCfg?.tipo === 'ANUAL') {
        if (tituloEl)  tituloEl.textContent  = 'Gastos por mês';
        if (tooltipEl) tooltipEl.textContent = 'Total gasto em cada mês do ano selecionado.';
        await carregarGastosPorMes(userId, params, el);
        return;
    }

    if (tituloEl)  tituloEl.textContent  = 'Gastos por dia da semana';
    if (tooltipEl) tooltipEl.textContent = 'Dias com mais gastos aparecem em vermelho; dias com menos gastos em azul.';
    el.innerHTML = carregando;

    const { ok, json } = await apiFetch(`${API_BASE}/dashboard/grafico/gastos-dia-semana/usuarios/${userId}?${params}`);
    if (!ok || !json?.dias?.length) { el.innerHTML = semDados; return; }

    const ABREV = {
        'segunda-feira': 'Seg', 'terça-feira': 'Ter', 'quarta-feira': 'Qua',
        'quinta-feira': 'Qui', 'sexta-feira': 'Sex', 'sábado': 'Sáb', 'domingo': 'Dom'
    };

    const cells = json.dias.map(d => {
        const abrev = ABREV[d.dia.toLowerCase()] || d.dia.slice(0, 3);
        const cor   = heatColor(d.normalizado);
        const valor = d.valorTotal > 0 ? CURRENCY.format(d.valorTotal) : '–';
        return `<div class="hm-cell" title="${d.dia}: ${valor}">
            <span class="hm-nome">${abrev}</span>
            <div class="hm-box" style="background:${cor};"></div>
            <span class="hm-valor">${valor}</span>
        </div>`;
    }).join('');

    el.innerHTML = `
        <div class="hm-wrap">
            <div class="hm-grid">${cells}</div>
            <div class="hm-legenda">
                <span class="hm-leg-txt">Menos Gastos</span>
                <div class="hm-grad"></div>
                <span class="hm-leg-txt">Mais Gastos</span>
            </div>
        </div>`;
}

