                { name: json.labelPeriodoAtual    || 'Período atual',    data: json.dados.map(d => Number(d.valorAtual)) },
                { name: json.labelPeriodoAnterior || 'Período anterior', data: json.dados.map(d => Number(d.valorAnterior)) }
            ],
